  1	import React, { FC, useMemo, useState } from 'react';
  2	
  3	import { useInstanceTypeVMStore } from '@catalog/CreateFromInstanceTypes/state/useInstanceTypeVMStore';
  4	import {
  5	  instanceTypeActionType,
  6	  InstanceTypes,
  7	} from '@catalog/CreateFromInstanceTypes/state/utils/types';
  8	import { groupVersionKindFromCommonResource } from '@catalog/CreateFromInstanceTypes/utils/utils';
  9	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 10	import { getName, getNamespace } from '@kubevirt-utils/resources/shared';
 11	import { NO_DATA_DASH } from '@kubevirt-utils/resources/vm/utils/constants';
 12	import { isAllNamespaces, isEmpty } from '@kubevirt-utils/utils/utils';
 13	import { ResourceLink, Timestamp, useActiveNamespace } from '@openshift-console/dynamic-plugin-sdk';
 14	import {
 15	  ActionList,
 16	  ActionListItem,
 17	  Bullseye,
 18	  Pagination,
 19	  SearchInput,
 20	} from '@patternfly/react-core';
 21	import { Table, TableVariant, Tbody, Td, Th, Thead, Tr } from '@patternfly/react-table';
 22	
 23	import UserProvidedInstanceTypesEmptyState from './components/UserProvidedInstanceTypesEmptyState';
 24	import useInstanceTypeListColumns from './hooks/useInstanceTypeListColumn';
 25	import { paginationDefaultValues, paginationInitialState } from './utils/constants';
 26	
 27	import './UserProvidedInstanceTypeList.scss';
 28	
 29	type UserProvidedInstanceTypesListProps = {
 30	  userProvidedInstanceTypes: InstanceTypes;
 31	};
 32	
 33	const UserProvidedInstanceTypesList: FC<UserProvidedInstanceTypesListProps> = ({
 34	  userProvidedInstanceTypes,
 35	}) => {
 36	  const { t } = useKubevirtTranslation();
 37	  const [activeNamespace] = useActiveNamespace();
 38	
 39	  const {
 40	    instanceTypeVMState: { selectedInstanceType },
 41	    setInstanceTypeVMState,
 42	  } = useInstanceTypeVMStore();
 43	
 44	  const [searchInput, setSearchInput] = useState('');
 45	  const [pagination, setPagination] = useState(paginationInitialState);
 46	
 47	  const onPaginationChange = ({ endIndex, page, perPage, startIndex }) => {
 48	    setPagination({
 49	      endIndex,
 50	      page,
 51	      perPage,
 52	      startIndex,
 53	    });
 54	  };
 55	
 56	  const filteredItems = useMemo(() => {
 57	    return userProvidedInstanceTypes.filter(
 58	      (opt) =>
 59	        isEmpty(searchInput) ||
 60	        getName(opt).toLowerCase().includes(searchInput.toString().toLowerCase()),
 61	    );
 62	  }, [searchInput, userProvidedInstanceTypes]);
 63	
 64	  const { columns, getSortType, sortedData } = useInstanceTypeListColumns(
 65	    filteredItems,
 66	    pagination,
 67	  );
 68	
 69	  if (isAllNamespaces(activeNamespace) && isEmpty(userProvidedInstanceTypes)) {
 70	    return (
 71	      <Bullseye className={'instance-type-list__all-projects'}>
 72	        {t('Select a project in order to see user-provided InstanceTypes')}
 73	      </Bullseye>
 74	    );
 75	  }
 76	
 77	  return (
 78	    <>
 79	      {!isEmpty(userProvidedInstanceTypes) && (
 80	        <ActionList className="instance-type-list__action-list">
 81	          <ActionListItem>
 82	            <SearchInput
 83	              aria-label="Filter menu items"
 84	              className="instance-type-list__search"
 85	              onChange={(_, value) => setSearchInput(value)}
 86	              placeholder={t('Search by name...')}
 87	              type="search"
 88	              value={searchInput}
 89	            />
 90	          </ActionListItem>
 91	          <ActionListItem>
 92	            <Pagination
 93	              onPerPageSelect={(_e, perPage, page, startIndex, endIndex) =>
 94	                onPaginationChange({ endIndex, page, perPage, startIndex })
 95	              }
 96	              onSetPage={(_e, page, perPage, startIndex, endIndex) =>
 97	                onPaginationChange({ endIndex, page, perPage, startIndex })
 98	              }
 99	              className="list-managment-group__pagination"
100	              isCompact
101	              itemCount={filteredItems?.length}
102	              page={pagination?.page}
103	              perPage={pagination?.perPage}
104	              perPageOptions={paginationDefaultValues}
105	            />
106	          </ActionListItem>
107	        </ActionList>
108	      )}
109	      {isEmpty(userProvidedInstanceTypes) || isEmpty(filteredItems) ? (
110	        <UserProvidedInstanceTypesEmptyState />
111	      ) : (
112	        <Table variant={TableVariant.compact}>
113	          <Thead>
114	            <Tr>
115	              {columns.map(({ id, title }, columnIndex) => (
116	                <Th key={id} sort={getSortType(columnIndex)}>
117	                  {title}
118	                </Th>
119	              ))}
120	            </Tr>
121	          </Thead>
122	          <Tbody>
123	            {sortedData.map((instanceType) => {
124	              const itName = getName(instanceType);
125	              const itNamespace = getNamespace(instanceType);
126	              return (
127	                <Tr
128	                  isRowSelected={
129	                    selectedInstanceType?.name === itName &&
130	                    selectedInstanceType?.namespace === itNamespace
131	                  }
132	                  onRowClick={() =>
133	                    setInstanceTypeVMState({
134	                      payload: { name: itName, namespace: itNamespace },
135	                      type: instanceTypeActionType.setSelectedInstanceType,
136	                    })
137	                  }
138	                  isClickable
139	                  isSelectable
140	                  key={itName}
141	                >
142	                  <Td>
143	                    <ResourceLink
144	                      groupVersionKind={groupVersionKindFromCommonResource(instanceType)}
145	                      linkTo={false}
146	                      name={itName}
147	                    />
148	                  </Td>
149	                  <Td>
150	                    <Timestamp timestamp={instanceType?.metadata?.creationTimestamp} />
151	                  </Td>
152	                  <Td>{instanceType?.metadata?.annotations?.description || NO_DATA_DASH}</Td>
153	                </Tr>
154	              );
155	            })}
156	          </Tbody>
157	        </Table>
158	      )}
159	    </>
160	  );
161	};
162	
163	export default UserProvidedInstanceTypesList;

